    // -------------------------------------------------------------------
    // Event forwarding
    // -------------------------------------------------------------------
    #[tauri::command]
    pub async fn start_event_stream(
        app_handle: tauri::AppHandle,
        engine: tauri::State<'_, Arc<AudioEngine>>,
        shutdown: tauri::State<'_, Arc<Notify>>,
    ) -> Result<(), String> {
        let engine = Arc::clone(&engine);
        let shutdown = Arc::clone(&shutdown);
        tauri::async_runtime::spawn(async move {
            let mut ticker = tokio::time::interval(Duration::from_millis(100));
            ticker.set_missed_tick_behavior(tokio::time::MissedTickBehavior::Skip);
            ticker.reset();
            loop {
                tokio::select! {
                    _ = shutdown.notified() => break,
                    _ = ticker.tick() => {
                        let mut drained = 0;
                        while let Some(event) = engine.poll_event() {
                            let _ = app_handle.emit("audio-event", event);
                            drained += 1;
                            if drained >= 256 {
                                break;
                            }
                        }
                    }
                }
            }
        });
        Ok(())
    }

    // -------------------------------------------------------------------
    // Persistent settings
    // -------------------------------------------------------------------
    use crate::settings::load_settings as settings_load;
    use crate::settings::save_settings as settings_save;
    use crate::settings::Settings as AppSettings;

    #[tauri::command]
    pub fn get_settings() -> Result<serde_json::Value, String> {
        let s = settings_load()?;
        Ok(serde_json::to_value(&s).map_err(|e| e.to_string())?)
    }

    #[tauri::command]
    pub fn set_settings(settings: serde_json::Value) -> Result<(), String> {
        let mut current: AppSettings = settings_load().unwrap_or_default();
        if let Ok(partial) = serde_json::from_value::<AppSettings>(settings) {
            if !partial.enabled_extensions.is_empty() {
                current.enabled_extensions = partial.enabled_extensions;
            }
            if partial.equalizer.is_some() {
                current.equalizer = partial.equalizer;
            }
            if partial.crossfade.is_some() {
                current.crossfade = partial.crossfade;
            }
            if partial.convolver.is_some() {
                current.convolver = partial.convolver;
            }
            if partial.lyric_font_size.is_some() {
                current.lyric_font_size = partial.lyric_font_size;
            }
        }
        settings_save(&current)?;
        Ok(())
    }

    // -------------------------------------------------------------------
    // Filesystem scan commands (Library page)
    // -------------------------------------------------------------------
    const SCAN_MAX_DEPTH: u32 = 8;
    const SCAN_MAX_ENTRIES: usize = 50_000;

    #[tauri::command]
    pub fn scan_directory(path: String) -> Result<Vec<FileEntry>, String> {
        let root = PathBuf::from(&path);
        if !root.is_dir() {
            return Err(format!("not a directory: {}", path));
        }
        read_dir_entries(&root).map_err(|e| e.to_string())
    }

    #[tauri::command]
    pub fn scan_library(
        roots: Vec<String>,
        extensions: Vec<String>,
    ) -> Result<Vec<FileEntry>, String> {
        let ext_set: HashSet<String> = extensions
            .into_iter()
            .map(|e| {
                let t = e.trim().to_lowercase();
                if t.starts_with('.') { t } else { format!(".{}", t) }
            })
            .collect();

        let mut entries = Vec::new();
        let mut visited = HashSet::new();

        for root_str in &roots {
            let root = PathBuf::from(root_str);
            let canon = root.canonicalize().unwrap_or_else(|_| root.clone());
            if !canon.is_dir() { continue; }
            walk_dir(&canon, 0, &ext_set, &mut visited, &mut entries);
            if entries.len() >= SCAN_MAX_ENTRIES { break; }
        }

        sort_entries(&mut entries);
        entries.truncate(SCAN_MAX_ENTRIES);
        Ok(entries)
    }

    fn read_dir_entries(dir: &Path) -> std::io::Result<Vec<FileEntry>> {
        let mut out = Vec::new();
        for entry in fs::read_dir(dir)? {
            let entry = match entry { Ok(e) => e, Err(_) => continue };
            let is_dir = entry.file_type().map(|ft| ft.is_dir()).unwrap_or(false);
            if let Some(fe) = build_file_entry(&entry.path(), is_dir) {
                out.push(fe);
            }
        }
        sort_entries(&mut out);
        Ok(out)
    }

    fn walk_dir(
        dir: &Path, depth: u32,
        ext_set: &HashSet<String>,
        visited: &mut HashSet<PathBuf>,
        out: &mut Vec<FileEntry>,
    ) {
        if depth >= SCAN_MAX_DEPTH { return; }
        let canon = dir.canonicalize().unwrap_or_else(|_| dir.to_path_buf());
        if !visited.insert(canon.clone()) { return; }

        let iter = match fs::read_dir(dir) {
            Ok(it) => it,
            Err(_) => { visited.remove(&canon); return; }
        };

        for entry in iter.flatten() {
            let path = entry.path();
            let is_dir = path.is_dir();
            if path.file_name()
                .and_then(|n| n.to_str())
                .map(|n| n.starts_with('.'))
                .unwrap_or(false)
            { continue; }

            if !is_dir {
                let ext = path.extension()
                    .and_then(|e| e.to_str())
                    .map(|e| format!(".{}", e.to_lowercase()));
                match ext {
                    Some(e) if ext_set.contains(&e) => {}
                    _ => continue,
                }
            }

            if let Some(fe) = build_file_entry(&path, is_dir) {
                out.push(fe);
            }
            if out.len() >= SCAN_MAX_ENTRIES { break; }
            if is_dir {
                walk_dir(&path, depth + 1, ext_set, visited, out);
                if out.len() >= SCAN_MAX_ENTRIES { break; }
            }
        }
        visited.remove(&canon);
    }

    fn build_file_entry(path: &Path, is_directory: bool) -> Option<FileEntry> {
        let name = path.file_name()?.to_str()?.to_string();
        let abs = path.canonicalize().unwrap_or_else(|_| path.to_path_buf());
        let abs_str = abs.to_string_lossy().into_owned();
        let (size, modified) = if is_directory {
            (None, None)
        } else {
            let meta = fs::metadata(path).ok();
            let size = meta.as_ref().map(|m| m.len());
            let modified = meta.and_then(|m| {
                m.modified().ok()
                    .and_then(|t| t.duration_since(UNIX_EPOCH).ok())
                    .map(|d| d.as_secs() as i64)
            });
            (size, modified)
        };
        Some(FileEntry {
            name, path: abs_str, is_directory, size, modified,
        })
    }

    fn sort_entries(entries: &mut [FileEntry]) {
        entries.sort_by(|a, b| {
            b.is_directory.cmp(&a.is_directory)
                .then_with(|| a.name.to_lowercase().cmp(&b.name.to_lowercase()))
        });
    }

